1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
14	
15	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
16	
17	const sumBasePremiums = (items: Item[]): number =>
18	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
19	
20	const quotePremium = (step: QuoteStep): number =>
21	  sumBasePremiums(step.items) + PROCESSING_FEE;
22	
23	export const runScenario = (input: unknown): unknown => {
24	  const scenario = input as Scenario;
25	  return {
26	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
27	  };
28	};
